import{_ as i,o as e,c as a,a2 as t}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"LOG.md — Deep32Q 巡檢日誌","description":"","frontmatter":{},"headers":[],"relativePath":"LOG.md","filePath":"LOG.md"}'),o={name:"LOG.md"};function r(n,l,s,p,d,u){return e(),a("div",null,[...l[0]||(l[0]=[t('<h1 id="log-md-—-deep32q-巡檢日誌" tabindex="-1">LOG.md — Deep32Q 巡檢日誌 <a class="header-anchor" href="#log-md-—-deep32q-巡檢日誌" aria-label="Permalink to &quot;LOG.md — Deep32Q 巡檢日誌&quot;">​</a></h1><h2 id="_2026-05-04-每日巡檢" tabindex="-1">[2026-05-04] 每日巡檢 <a class="header-anchor" href="#_2026-05-04-每日巡檢" aria-label="Permalink to &quot;[2026-05-04] 每日巡檢&quot;">​</a></h2><ul><li>市場情緒：✅ 完成（S&amp;P 500 創高、中東戰事、Fed 領導交接、台股 38,926）</li><li>黃豆追蹤：✅ 完成（現貨 $11.38、年漲 +13.25%、USDA 壓榨創新高）</li><li>黃金追蹤：✅ 完成（現貨 $4,614、Q1 央行購金創新高 337 噸）</li><li>drop/ 掃描：✅ 完成（黃金任務已歸檔、光通訊供應鏈待處理、2 PDF 已歸檔）</li><li>CRM 電話對應 input 框 bug 修復：✅ commit 3b51783（欄位對應畫面選標準標籤後不再顯示多餘 input 框，改為僅「自訂」時顯示）</li></ul><h2 id="_2026-06-04-班內生管理系統-—-最終設計確認-開工" tabindex="-1">[2026-06-04] 班內生管理系統 — 最終設計確認 &amp; 開工 <a class="header-anchor" href="#_2026-06-04-班內生管理系統-—-最終設計確認-開工" aria-label="Permalink to &quot;[2026-06-04] 班內生管理系統 — 最終設計確認 &amp; 開工&quot;">​</a></h2><h3 id="最終工作流程-vfinal-經使用者確認開工" tabindex="-1">最終工作流程（vFinal，經使用者確認開工） <a class="header-anchor" href="#最終工作流程-vfinal-經使用者確認開工" aria-label="Permalink to &quot;最終工作流程（vFinal，經使用者確認開工）&quot;">​</a></h3><p><strong>系統名稱</strong>：班內生管理系統 <strong>架構</strong>：</p><ul><li>資料庫：<code>winchamp_enrollments</code>（MariaDB on NAS 100.97.10.122）</li><li>表單：公開頁面掛在 port 5999</li><li>後端管理：掛在 CRM 內聊天室發送填表連結</li><li>莘莘自動化：Python requests，每次執行先 login 拿 JWT</li></ul><p><strong>系統學號規則</strong>：<code>[校區前綴] + [入學學年度三碼] + [序號三碼]</code></p><ul><li>TY=桃園旗艦校、WL=武陵悅思專校、NL=內壢旗艦校</li><li>年級→入學年：國三=民國年+1、高一=民國年、高二=民國年−1、高三=民國年−2</li><li>序號暫從 001 開始（待使用者提供正確數字）</li></ul><p><strong>表單送出自動化（雙軌）</strong>：</p><ol><li>寫入本機 DB（status=pending）</li><li>本機計算系統學號</li><li>登入莘莘拿 JWT</li><li>POST 學生資料給莘莘（含自編學號）</li><li>成功→DB 記錄莘莘 student UUID、status=pushed</li><li>失敗→DB 記錄錯誤、status=failed</li></ol><p><strong>後端編輯同步</strong>：後端管理員修改學生資料 → 儲存時自動 PUT 莘莘 API 同步</p><p><strong>後端管理頁面</strong>：類比名冊管理系統搜尋頁面</p><p><strong>模型對話流程</strong>：</p><ul><li>校區前綴/年級邏輯經多次對接確認</li><li>學號由本機產生、一併傳莘莘（非先取莘莘學號）</li><li>莘莘只有兩件事：建立成功（回傳 UUID）、建立失敗</li><li>後端編輯要 PUT 同步莘莘</li></ul><p><strong>版控</strong>：CRM repo f96869a, work repo bf95e3e</p>',16)])])}const h=i(o,[["render",r]]);export{_ as __pageData,h as default};
